module binary_counter(clk, enable, count);  

    input  clk;  
    input  enable;  
    output  [1:0] count;  
    reg   [1:0]  count; 
    initial count = 0;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
          begin
            if (enable)
                count <= count + 1;
          end  

endmodule
